import{_ as a,o as d,c as e,a2 as r}from"./chunks/framework.TWA1q3r6.js";const b=JSON.parse('{"title":"👶 0-3M · 感官校准期","description":"","frontmatter":{"title":"👶 0-3M · 感官校准期"},"headers":[],"relativePath":"stages/0-3m.md","filePath":"stages/0-3m.md"}'),s={name:"stages/0-3m.md"};function i(n,t,o,l,h,c){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="👶-0-3m-·-感官校准期" tabindex="-1">👶 0-3M · 感官校准期 <a class="header-anchor" href="#👶-0-3m-·-感官校准期" aria-label="Permalink to &quot;👶 0-3M · 感官校准期&quot;">​</a></h1><blockquote><p>这个世界好大，而你的声音好近。</p><p>趴着、看脸、听说话、被抱着 —— 这就是这个阶段的全部&quot;课程&quot;。</p></blockquote><hr><h2 id="🎯-发展里程碑" tabindex="-1">🎯 发展里程碑 <a class="header-anchor" href="#🎯-发展里程碑" aria-label="Permalink to &quot;🎯 发展里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>科学项目</th><th>在做什么</th><th>每天多久</th><th>来源</th></tr></thead><tbody><tr><td>大运动</td><td><strong>Tummy Time</strong> 趴卧</td><td>练颈部/肩部/核心肌群，预防扁头</td><td>清醒时15-30min，分多次</td><td>AAP</td></tr><tr><td>视觉</td><td><strong>黑白卡</strong>（20-30cm）</td><td>新生儿视力仅20/400，高对比度促进视神经发育</td><td>每次2-5min</td><td>AAP</td></tr><tr><td>语言</td><td><strong>Parentese对话</strong></td><td>夸张语调的母语对话加速听觉皮层发育</td><td>融入喂养/换尿布</td><td>Kuhl</td></tr><tr><td>依附</td><td><strong>肌肤接触</strong> Skin-to-Skin</td><td>稳定心率体温 + 催产素双向分泌 → 安全依附</td><td>每天≥1h</td><td>WHO</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">极简原则 ✨</p><p>这个阶段不需要任何课程、教具或App。只需要：趴着、看脸、听说话、被抱着。</p></div><hr><h2 id="🛡️-装备清单" tabindex="-1">🛡️ 装备清单 <a class="header-anchor" href="#🛡️-装备清单" aria-label="Permalink to &quot;🛡️ 装备清单&quot;">​</a></h2><h3 id="安全必备-safety-core" tabindex="-1">安全必备 Safety Core <a class="header-anchor" href="#安全必备-safety-core" aria-label="Permalink to &quot;安全必备 Safety Core&quot;">​</a></h3><h4 id="🚗-汽车安全座椅-后向式-essential" tabindex="-1">🚗 汽车安全座椅（后向式） <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🚗-汽车安全座椅-后向式-essential" aria-label="Permalink to &quot;🚗 汽车安全座椅（后向式） Essential&quot;">​</a></h4><p>后向安装降低 <strong>75%</strong> 严重伤害率。出院回家第一天就需要。（AAP/CPSC）</p><p><strong>选购</strong></p><table tabindex="0"><thead><tr><th>推荐</th><th>品牌</th><th>亮点</th><th>入手价</th></tr></thead><tbody><tr><td>首选</td><td>Cybex Sirona Gi 🇩🇪</td><td>i-Size + ADAC高分 + 后向至105cm + 残值45-55%</td><td>≤¥3,200（双11）</td></tr><tr><td>性价比</td><td>Joie i-Spin 🇬🇧</td><td>同级i-Size认证，价格仅Cybex的60%</td><td>—</td></tr><tr><td>国产优选</td><td>猫头鹰妙转Ultra</td><td>i-Size + 3C双认证 + 莫兰迪色系</td><td>≤¥2,500</td></tr></tbody></table><h4 id="🛏️-婴儿床-essential" tabindex="-1">🛏️ 婴儿床 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🛏️-婴儿床-essential" aria-label="Permalink to &quot;🛏️ 婴儿床 Essential&quot;">​</a></h4><p>栅栏间距 ≤6cm，床内无软质物，降低SIDS风险。（AAP）</p><p><strong>选购</strong></p><table tabindex="0"><thead><tr><th>推荐</th><th>品牌</th><th>亮点</th><th>入手价</th></tr></thead><tbody><tr><td>传世之选</td><td>Stokke Sleepi</td><td>0-5Y三段变形 + 榉木 + 残值60-70%</td><td>≤¥7,500（618）</td></tr><tr><td>艺术品</td><td>Leander Classic 🇩🇰</td><td>丹麦设计奖 + 弧形雕塑感</td><td>—</td></tr><tr><td>ROI之王</td><td>IKEA SNIGLAR</td><td>满足全部安全标准，¥499不择时</td><td>¥499</td></tr></tbody></table><h4 id="😴-睡袋-sleep-sack-essential" tabindex="-1">😴 睡袋 Sleep Sack <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#😴-睡袋-sleep-sack-essential" aria-label="Permalink to &quot;😴 睡袋 Sleep Sack Essential&quot;">​</a></h4><p>替代散落毯子，AAP安全睡眠核心建议。（AAP）</p><p><strong>选购</strong></p><table tabindex="0"><thead><tr><th>推荐</th><th>品牌</th><th>亮点</th></tr></thead><tbody><tr><td>首选</td><td>ergoPouch 🇦🇺</td><td>TOG分级科学对应室温 + GOTS有机棉</td></tr><tr><td>医院同款</td><td>HALO SleepSack</td><td>AAP官方合作 + NICU标配</td></tr><tr><td>国产优选</td><td>Babycare / 英氏</td><td>A类面料 + 莫兰迪色 + 进口25-30%价格</td></tr></tbody></table><h4 id="☀️-维生素d-400iu-日-essential" tabindex="-1">☀️ 维生素D 400IU/日 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#☀️-维生素d-400iu-日-essential" aria-label="Permalink to &quot;☀️ 维生素D 400IU/日 Essential&quot;">​</a></h4><p>母乳中VD不足，每天补充400IU预防佝偻病，从出生开始。（AAP/卫健委）</p><p><strong>选购</strong> Ddrops / 星鲨 / 悦而，约 ¥50-150/瓶</p><h4 id="🌡️-医用体温计-essential" tabindex="-1">🌡️ 医用体温计 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🌡️-医用体温计-essential" aria-label="Permalink to &quot;🌡️ 医用体温计 Essential&quot;">​</a></h4><p>新生儿发热 ≥38°C 需紧急评估，家里必备一支准确的体温计。（AAP）</p><p><strong>选购</strong> Braun耳温枪 / 欧姆龙 ¥100-400</p><h3 id="便利好物" tabindex="-1">便利好物 <a class="header-anchor" href="#便利好物" aria-label="Permalink to &quot;便利好物&quot;">​</a></h3><h4 id="🧷-纸尿裤-essential" tabindex="-1">🧷 纸尿裤 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🧷-纸尿裤-essential" aria-label="Permalink to &quot;🧷 纸尿裤 Essential&quot;">​</a></h4><p>保护皮肤屏障，降低尿布皮炎。消耗品，优先价格和亲肤性。</p><p><strong>选购</strong> 花王妙而舒 / 大王天使 / 好奇铂金装，先买试用装确认不过敏</p><h4 id="🦘-婴儿背带-m型腿位-conditional" tabindex="-1">🦘 婴儿背带（M型腿位） <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🦘-婴儿背带-m型腿位-conditional" aria-label="Permalink to &quot;🦘 婴儿背带（M型腿位） Conditional&quot;">​</a></h4><p>髋关节友好设计，有利于亲密依附。3月龄后颈部支撑力增强，体验更好。</p><p><strong>选购</strong> Ergobaby Omni 360 / BabyBjörn One ¥500-1,500</p><h3 id="妈妈必做" tabindex="-1">妈妈必做 <a class="header-anchor" href="#妈妈必做" aria-label="Permalink to &quot;妈妈必做&quot;">​</a></h3><h4 id="🏥-产后42天复查-essential" tabindex="-1">🏥 产后42天复查 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🏥-产后42天复查-essential" aria-label="Permalink to &quot;🏥 产后42天复查 Essential&quot;">​</a></h4><p>子宫复旧 + 盆底评估 + 产后抑郁筛查（Edinburgh量表）。这次检查别跳过。</p><p><strong>选购</strong> 建档医院产科，产后42天常规复查</p><h4 id="🍼-吸奶器-conditional" tabindex="-1">🍼 吸奶器 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🍼-吸奶器-conditional" aria-label="Permalink to &quot;🍼 吸奶器 Conditional&quot;">​</a></h4><p>职场妈妈或乳腺炎管理必需，全母乳亲喂可不需要。</p><p><strong>选购</strong></p><table tabindex="0"><thead><tr><th>推荐</th><th>品牌</th><th>亮点</th><th>入手价</th></tr></thead><tbody><tr><td>首选</td><td>Spectra S1+ 🇰🇷</td><td>医院级 + 闭合系统 + 静音&lt;45dB</td><td>≤¥1,300</td></tr><tr><td>临床之王</td><td>Medela Swing Maxi</td><td>全球NICU份额第一</td><td>—</td></tr><tr><td>颜值担当</td><td>Elvie Stride</td><td>穿戴免手持 + 工业设计奖</td><td>—</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">❌ 避坑清单</p><ul><li><strong>婴儿床围 Crib Bumpers</strong> — CPSC 2022立法禁售，窒息致死因果链明确</li><li><strong>定型枕</strong> — AAP禁止1岁内任何枕头（SIDS风险），扁头多数自愈，Tummy Time是最好的预防</li><li><strong>游泳脖圈</strong> — 颈椎压迫 + 滑脱窒息风险，零发育收益。替代：大人一对一水中托抱</li><li><strong>恒温调奶器</strong> — 保温壶 + 温度计完全够用</li><li><strong>婴儿专用洗衣液</strong> — 普通无香型洗衣液就行</li></ul></div><hr><h2 id="🌟-新生儿期多巴胺准备金" tabindex="-1">🌟 新生儿期多巴胺准备金 <a class="header-anchor" href="#🌟-新生儿期多巴胺准备金" aria-label="Permalink to &quot;🌟 新生儿期多巴胺准备金&quot;">​</a></h2><blockquote><p>最疲惫的日子里，这些小物件让生活多一点暖意。</p></blockquote><table tabindex="0"><thead><tr><th>物品</th><th>为什么值得</th><th>参考方向</th><th>预算</th></tr></thead><tbody><tr><td>✂️ 婴儿指甲剪（日式精工）</td><td>每周剪2次，好工具减少焦虑，用3年+</td><td>贝印(KAI) / Pigeon</td><td>¥30-80</td></tr><tr><td>🌙 高颜值夜灯</td><td>夜奶/换尿布刚需，暖光≤3000K不干扰褪黑素</td><td>Yeelight / Mushie硅胶</td><td>¥50-200</td></tr><tr><td>🪝 黄铜/木质衣帽架</td><td>挂婴儿小衣服 = 治愈视觉，功能+装饰一体</td><td>HAY Knit / 木墨</td><td>¥200-600</td></tr><tr><td>📷 出生纪念物</td><td>一张黑白胶片照 &gt; 任何影楼百天照</td><td>本地独立摄影师</td><td>¥0-2,000</td></tr></tbody></table>',47)])])}const u=a(s,[["render",i]]);export{b as __pageData,u as default};
